LAYER
  NAME "mapa_precipitacion_media_anual"
  GROUP "Climatología"
  STATUS off
  MAXSCALE -1.0
  MINSCALE -1.0
  TYPE polygon
  PROCESSING 'LABEL_NO_CLIP=1'
  CLASSITEM "precipitacion_anual"  
  TRANSPARENCY 100
  DUMP true
  TEMPLATE void 
  DATA "the_geom from (select gid, precipitacion_anual, the_geom from geo.mapa_precipitacion_media_anual) as siar using unique gid using srid=32718"
